  "inlineSchema": "// schema.prisma — Tempest Finance PWA\n// Prinsip: Clean Code, DRY, KISS, SoC\n// Komunikasi DB hanya via: prisma migrate dev & prisma generate\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n}\n\n// ============================================================\n// MODEL USER — Autentikasi Pengguna (PIN 6 Digit)\n// ============================================================\nmodel User {\n  id         String   @id @default(cuid())\n  name       String\n  pin        String   @unique\n  isApproved Boolean  @default(false)\n  createdAt  DateTime @default(now())\n\n  // ─── Relasi balik: data milik user ini ───────────────────\n  accounts     Account[]\n  categories   Category[]\n  transactions Transaction[]\n  budgets      Budget[]\n  debts        Debt[]\n  debtPayments DebtPayment[]\n}\n\n// ============================================================\n// MODEL ACCOUNT — Mewakili setiap akun keuangan pengguna\n// ============================================================\nmodel Account {\n  id        String   @id @default(cuid())\n  name      String\n  balance   Float    @default(0)\n  uangGoib  Float    @default(0)\n  icon      String?\n  color     String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // ─── Self-relation: Parent → Children (Kantong) ───────────\n  parentId String?\n  parent   Account?  @relation(\"SubAccounts\", fields: [parentId], references: [id], onDelete: Cascade)\n  children Account[] @relation(\"SubAccounts\")\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  transactions Transaction[] @relation(\"AccountTransactions\")\n  transfersIn  Transaction[] @relation(\"TransferTo\")\n}\n\n// ============================================================\n// MODEL CATEGORY — Klasifikasi transaksi (mendukung Parent/Child)\n// Contoh: Makan (Parent) → Kopi, Snack (Children)\n// ============================================================\nmodel Category {\n  id    String  @id @default(cuid())\n  name  String\n  type  String // \"INCOME\" atau \"EXPENSE\"\n  icon  String?\n  order Int     @default(0) // Urutan tampil di UI\n\n  // ─── Self-relation: Parent → Children ────────────────────\n  // parentId null = kategori root/parent\n  parentId String?\n  parent   Category?  @relation(\"SubCategories\", fields: [parentId], references: [id], onDelete: SetNull)\n  children Category[] @relation(\"SubCategories\")\n\n  // ─── Relasi ke User ──────────────────────────────────────\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  transactions Transaction[]\n  budgets      Budget[]\n}\n\n// ============================================================\n// MODEL TRANSACTION — Data inti setiap transaksi keuangan\n// ============================================================\nmodel Transaction {\n  id          String   @id @default(cuid())\n  amount      Float\n  type        String // \"INCOME\" | \"EXPENSE\" | \"TRANSFER\"\n  description String?\n  date        DateTime @default(now())\n  createdAt   DateTime @default(now())\n  isSynced    Boolean  @default(false)\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  accountId String\n  account   Account @relation(\"AccountTransactions\", fields: [accountId], references: [id])\n\n  categoryId String?\n  category   Category? @relation(fields: [categoryId], references: [id])\n\n  toAccountId String?\n  toAccount   Account? @relation(\"TransferTo\", fields: [toAccountId], references: [id])\n\n  adminFee Float? @default(0)\n}\n\n// ============================================================\n// MODEL BUDGET — Batas pengeluaran per kategori per periode\n// Contoh: Makan max Rp 2.000.000 / bulan\n// ============================================================\nmodel Budget {\n  id     String @id @default(cuid())\n  amount Float // Batas maksimal\n  period String @default(\"MONTHLY\") // \"MONTHLY\" | \"WEEKLY\"\n\n  categoryId String\n  category   Category @relation(fields: [categoryId], references: [id], onDelete: Cascade)\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Satu budget per user per kategori per periode\n  @@unique([userId, categoryId, period])\n}\n\n// ============================================================\n// MODEL DEBT — Pencatat Hutang & Piutang\n// HUTANG = kita yang berhutang ke orang lain\n// PIUTANG = orang lain yang berhutang ke kita\n// ============================================================\nmodel Debt {\n  id          String    @id @default(cuid())\n  type        String // \"HUTANG\" | \"PIUTANG\"\n  personName  String // Nama orang yang terlibat\n  amount      Float // Nominal\n  description String? // Catatan opsional\n  dueDate     DateTime? // Jatuh tempo opsional\n  isPaid      Boolean   @default(false)\n  paidAt      DateTime? // Kapan dilunasi\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  payments DebtPayment[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// ============================================================\n// MODEL DEBTPAYMENT — Riwayat angsuran/cicilan hutang/piutang\n// ============================================================\nmodel DebtPayment {\n  id     String   @id @default(cuid())\n  amount Float\n  date   DateTime @default(now())\n\n  debtId String\n  debt   Debt   @relation(fields: [debtId], references: [id], onDelete: Cascade)\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n",
